import{_ as r,c as s,o,ag as n}from"./chunks/framework.GdcW6lnn.js";const P=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"basics_api/https-tls.md","filePath":"basics_api/https-tls.md"}'),l={name:"basics_api/https-tls.md"};function i(T,t,e,g,S,p){return o(),s("div",null,t[0]||(t[0]=[n('<h3 id="🔒-https-tls-http-secure-transport-layer-security-забезпечення-безпечноі-передачі-даних" tabindex="-1">🔒 HTTPS/TLS (HTTP Secure/Transport Layer Security): Забезпечення безпечної передачі даних <a class="header-anchor" href="#🔒-https-tls-http-secure-transport-layer-security-забезпечення-безпечноі-передачі-даних" aria-label="Permalink to “🔒 HTTPS/TLS (HTTP Secure/Transport Layer Security): Забезпечення безпечної передачі даних”">​</a></h3><p><strong>Що це?</strong></p><p>HTTPS (HTTP Secure) - це <strong>безпечна версія протоколу HTTP</strong>, основного протоколу для передачі даних у World Wide Web. Безпека в HTTPS забезпечується використанням протоколів <strong>TLS (Transport Layer Security)</strong> або його застарілої версії <strong>SSL (Secure Sockets Layer)</strong>. HTTPS шифрує дані, що передаються між браузером (або іншим клієнтом) та веб-сервером (або API-сервером), забезпечуючи їхню конфіденційність та цілісність.</p><p><strong>Як це працює?</strong></p><p>Основний принцип роботи HTTPS полягає у встановленні <strong>зашифрованого з&#39;єднання</strong> між клієнтом та сервером перед передачею будь-яких чутливих даних. Цей процес включає такі етапи:</p><ol><li><p><strong>TCP Handshake:</strong> Клієнт і сервер встановлюють звичайне TCP-з&#39;єднання.</p></li><li><p><strong>TLS/SSL Handshake (Рукостискання):</strong> Після встановлення TCP-з&#39;єднання відбувається процес &quot;рукостискання&quot; TLS/SSL, під час якого клієнт і сервер домовляються про параметри безпечного з&#39;єднання:</p><ul><li><strong>Узгодження протоколу:</strong> Клієнт і сервер домовляються про версію протоколу TLS/SSL, яку вони будуть використовувати.</li><li><strong>Обмін криптографічними можливостями:</strong> Клієнт і сервер обмінюються інформацією про підтримувані криптографічні алгоритми (шифри) для шифрування, автентифікації та обміну ключами.</li><li><strong>Сервер надсилає сертифікат:</strong> Сервер надсилає клієнту свій <strong>сертифікат SSL/TLS</strong>. Цей сертифікат містить: <ul><li>Інформацію про ідентичність сервера (доменне ім&#39;я).</li><li>Публічний ключ сервера.</li><li>Інформацію про центр сертифікації (CA), який видав сертифікат, та його цифровий підпис.</li></ul></li><li><strong>Перевірка сертифіката клієнтом:</strong> Клієнт перевіряє дійсність сертифіката сервера, зокрема: <ul><li>Чи виданий сертифікат довіреним CA (браузери мають вбудований список довірених CA).</li><li>Чи відповідає доменне ім&#39;я в сертифікаті доменному імені сервера, до якого відбувається підключення.</li><li>Чи не закінчився термін дії сертифіката.</li><li>Чи не був сертифікат відкликаний.</li></ul></li><li><strong>Генерація та обмін сеансовими ключами:</strong> Клієнт генерує випадковий <strong>сеансовий ключ</strong> (симетричний ключ), який буде використовуватися для шифрування фактичних даних. Цей сеансовий ключ шифрується за допомогою публічного ключа сервера, отриманого з сертифіката, та надсилається серверу.</li><li><strong>Розшифрування сеансового ключа:</strong> Сервер використовує свій приватний ключ (який відповідає публічному ключу в сертифікаті) для розшифрування отриманого сеансового ключа.</li><li><strong>Встановлення зашифрованого з&#39;єднання:</strong> Тепер і клієнт, і сервер мають спільний секретний сеансовий ключ, який вони використовуватимуть для симетричного шифрування та розшифрування всіх подальших даних, що передаються між ними. Симетричне шифрування є значно швидшим за асиметричне, що використовується на етапі рукостискання.</li></ul></li><li><p><strong>Зашифрована передача даних:</strong> Після успішного завершення рукостискання всі HTTP-дані (запити та відповіді), включаючи URL, заголовки, тіло запиту та тіло відповіді, шифруються за допомогою узгодженого сеансового ключа та криптографічного алгоритму. Це робить дані незрозумілими для будь-кого, хто може перехопити трафік.</p></li></ol><p><strong>Переваги використання HTTPS/TLS:</strong></p><ul><li><strong>Конфіденційність:</strong> Забезпечує шифрування даних, запобігаючи їхньому перехопленню та прочитанню третіми особами (наприклад, хакерами, інтернет-провайдерами). Це особливо важливо для передачі чутливої інформації, такої як паролі, дані кредитних карток, персональні дані.</li><li><strong>Цілісність даних:</strong> TLS/SSL також забезпечує цілісність даних за допомогою механізмів виявлення підробок (MAC - Message Authentication Code). Це гарантує, що дані не були непомітно змінені під час передачі.</li><li><strong>Автентичність сервера:</strong> Сертифікат SSL/TLS, виданий довіреним CA, допомагає клієнту переконатися, що він спілкується з легітимним сервером, а не з підробленим сайтом (хоча це більше стосується перевірки домену, а не особистості власника).</li><li><strong>SEO-рейтинг:</strong> Google та інші пошукові системи надають перевагу веб-сайтам, що використовують HTTPS, що може позитивно вплинути на їхній рейтинг у пошуковій видачі.</li><li><strong>Довіра користувачів:</strong> Значок замка 🔒 у адресному рядку браузера вказує на використання HTTPS, що підвищує довіру користувачів до веб-сайту або API.</li></ul><p><strong>Важливість для API:</strong></p><p>Використання HTTPS/TLS є <strong>абсолютно необхідним</strong> для будь-якого сучасного API, особливо якщо він обробляє будь-які конфіденційні дані або вимагає аутентифікації. Без HTTPS дані, що передаються через API, можуть бути легко перехоплені та використані зловмисниками.</p><p><strong>Реалізація HTTPS/TLS:</strong></p><p>Для впровадження HTTPS/TLS для вашого API або веб-сайту необхідно:</p><ol><li><strong>Отримати сертифікат SSL/TLS:</strong> Сертифікат можна придбати у комерційного центру сертифікації (CA) або отримати безкоштовно від таких ініціатив, як Let&#39;s Encrypt. Вибір залежить від ваших потреб та рівня довіри, який ви хочете забезпечити.</li><li><strong>Налаштувати веб-сервер:</strong> Веб-сервер (наприклад, Apache, Nginx, IIS) потрібно налаштувати для використання отриманого сертифіката та приватного ключа. Це включає вказівку шляхів до файлів сертифіката та ключа, а також налаштування портів (зазвичай порт 443 для HTTPS).</li><li><strong>Перенаправлення HTTP на HTTPS (рекомендовано):</strong> Налаштуйте веб-сервер для автоматичного перенаправлення всіх запитів, що надходять на незахищений порт HTTP (зазвичай порт 80), на відповідний HTTPS URL.</li><li><strong>Забезпечення використання HTTPS у клієнтському коді:</strong> Переконайтеся, що всі клієнтські додатки та веб-сторінки звертаються до вашого API за протоколом <code>https://</code>.</li></ol><p><strong>Висновок:</strong></p><p>HTTPS/TLS є критично важливими технологіями для забезпечення безпеки та конфіденційності передачі даних в Інтернеті. Їхнє використання є обов&#39;язковим для захисту як користувачів, так і веб-сервісів та API від широкого спектру загроз безпеки.</p>',15)]))}const c=r(l,[["render",i]]);export{P as __pageData,c as default};
